18	    const signature = req.headers['x-signature'] as string | undefined;
19	
20	    if (!apiKey || !timestamp || !signature) {
21	      res.status(401).json({ success: false, error: 'Missing API signing headers' });
22	      return;
23	    }
24	
25	    const tsMs = parseInt(timestamp, 10);
26	    if (isNaN(tsMs) || Math.abs(Date.now() - tsMs) > 5 * 60 * 1000) {
27	      res.status(401).json({ success: false, error: 'Request timestamp out of acceptable range' });
28	      return;
29	    }
30	
31	    const secret = await getSecretByKey(apiKey);
32	    if (!secret) {
33	      res.status(401).json({ success: false, error: 'Unknown API key' });
34	      return;
35	    }
36	
37	    const body = typeof req.body === 'object' ? JSON.stringify(req.body) : (req.body ?? '');
38	    const signaturePayload = `${req.method}:${req.path}:${timestamp}:${body}`;
39	    const expected = crypto.createHmac('sha256', secret).update(signaturePayload).digest('hex');
40	
41	    if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected))) {
42	      logger.warn({ msg: 'Invalid API signature', apiKey, path: req.path });
43	      res.status(401).json({ success: false, error: 'Invalid signature' });
44	      return;
45	    }
46	
47	    next();
48	  };
49	}
