  '/:id',
  authenticate,
  requirePermission('shipment:read'),
  getShipmentHandler,
);

router.patch(
  '/:id/status',
  authenticate,
  requirePermission('shipment:intervene'),
  updateStatusHandler,
);

router.post(
  '/sync/:carrierId',
  authenticate,
  requirePermission('shipment:intervene'),
  triggerSyncHandler,
);

export default router;

