49	/** Verifies an HMAC-SHA256 signed request â€” used by API signing middleware. */
50	export async function verifyApiSignature(
51	  keyId: string,
52	  method: string,
53	  path: string,
54	  timestamp: string,
55	  body: string,
56	  signature: string
57	): Promise<boolean> {
58	  const key = await prisma.integrationKey.findUnique({ where: { keyId } });
59	  if (!key || !key.isActive) return false;
60	
61	  // Reject timestamps older than 5 minutes
62	  const tsMs = parseInt(timestamp, 10);
63	  if (isNaN(tsMs) || Math.abs(Date.now() - tsMs) > 5 * 60 * 1000) return false;
