/**
 * API functional tests â€” /health endpoints
 * Requires the backend to be running against a test database.
 */
import request from 'supertest';
import { createApp } from '../../src/app';

process.env.NODE_ENV = 'test';
process.env.ENCRYPTION_KEY = 'a'.repeat(64);
process.env.JWT_SECRET = 'test-jwt-secret-not-for-production';
process.env.DATABASE_URL = process.env.TEST_DATABASE_URL ?? 'mysql://campusops:test@localhost:3306/campusops_test';
process.env.REDIS_URL = process.env.TEST_REDIS_URL ?? 'redis://localhost:6379';

describe('Health endpoints', () => {
  const app = createApp();

  it('GET /health returns 200 with status ok', async () => {
    const res = await request(app).get('/health');
    expect(res.status).toBe(200);
    expect(res.body.status).toBe('ok');
    expect(typeof res.body.uptime).toBe('number');
  });

  it('GET /health/info returns service metadata', async () => {
    const res = await request(app).get('/health/info');
    expect(res.status).toBe(200);
    expect(res.body.name).toBe('campusops-backend');
    expect(res.body.environment).toBe('test');
  });

  it('GET /api/unknown returns 404 JSON', async () => {
    const res = await request(app).get('/api/does-not-exist');
    expect(res.status).toBe(404);
    expect(res.body.success).toBe(false);
    expect(res.body.code).toBe('NOT_FOUND');
  });

  it('POST /api/unknown with no idempotency key on non-existent endpoint returns JSON error', async () => {
    const res = await request(app)
      .post('/api/does-not-exist')
      .send({ foo: 'bar' });
    expect([404, 400]).toContain(res.status);
    expect(res.body.success).toBe(false);
  });
});

