import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { config } from '../config';
import type { UserRole, AuthenticatedUser } from '../types';
import { can, type Permission } from '../lib/permissions';
import { getRedisClient } from '../lib/redis';

declare global {
  namespace Express {
    interface Request {
      user?: AuthenticatedUser;
      correlationId: string;
    }
  }
}

/** JWT authentication â€” attaches req.user or returns 401 */
export function authenticate(req: Request, res: Response, next: NextFunction): void {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    res.status(401).json({ success: false, error: 'Missing or invalid Authorization header', code: 'UNAUTHORIZED' });
    return;
  }

  const token = authHeader.slice(7);
  try {
    const payload = jwt.verify(token, config.jwt.secret) as AuthenticatedUser & { jti?: string };

    // Check token blacklist (revoked tokens, e.g. after logout)
    const jti = payload.jti;
    if (jti) {
      getRedisClient().get(`campusops:revoked:${jti}`).then((revoked) => {
        if (revoked) {
          res.status(401).json({ success: false, error: 'Token has been revoked', code: 'TOKEN_REVOKED' });
          return;
        }
        req.user = { id: payload.id, username: payload.username, role: payload.role };
        next();
      }).catch(() => {
        // Fail open on Redis error â€” don't block legitimate traffic
        req.user = { id: payload.id, username: payload.username, role: payload.role };
        next();
      });
    } else {
      req.user = { id: payload.id, username: payload.username, role: payload.role };
      next();
    }
  } catch {
    res.status(401).json({ success: false, error: 'Invalid or expired token', code: 'UNAUTHORIZED' });
  }
}

/** Role-based authorization â€” used when you know the exact roles */
export function authorize(...roles: UserRole[]) {
  return (req: Request, res: Response, next: NextFunction): void => {
    if (!req.user) {
      res.status(401).json({ success: false, error: 'Unauthenticated', code: 'UNAUTHORIZED' });
      return;
    }
    if (!roles.includes(req.user.role)) {
      res.status(403).json({ success: false, error: 'Insufficient permissions', code: 'FORBIDDEN' });
      return;
    }
    next();
  };
}

/** Permission-based authorization â€” preferred, uses the permission matrix */
export function requirePermission(permission: Permission) {
  return (req: Request, res: Response, next: NextFunction): void => {
    if (!req.user) {
      res.status(401).json({ success: false, error: 'Unauthenticated', code: 'UNAUTHORIZED' });
      return;
    }
    if (!can(req.user.role, permission)) {
      res.status(403).json({
        success: false,
        error: `Permission denied: ${permission}`,
        code: 'FORBIDDEN',
      });
      return;
    }
    next();
  };
}

/** Auditor guard â€” allows read access but blocks all write operations */
export function denyAuditorWrites(req: Request, res: Response, next: NextFunction): void {
  if (req.user?.role === 'auditor' && ['POST', 'PUT', 'PATCH', 'DELETE'].includes(req.method)) {
    res.status(403).json({
      success: false,
      error: 'Auditors have read-only access',
      code: 'FORBIDDEN',
    });
    return;
  }
  next();
}

import { Request, Response, NextFunction } from 'express';
import { getRedisClient } from '../lib/redis';
import { logger } from '../lib/logger';

const IDEMPOTENCY_TTL_SECONDS = 86_400; // 24 hours
const UUID_V4_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

/**
 * Idempotency middleware for mutating endpoints.
 * Requires X-Idempotency-Key header (UUIDv4).
 * On duplicate key within 24h: returns cached response without re-processing.
 * Fail-open on Redis errors so transient Redis issues don't block requests.
 */
export function idempotency(req: Request, res: Response, next: NextFunction): void {
  const key = req.headers['x-idempotency-key'] as string | undefined;

  if (!key) {
    res.status(400).json({ success: false, error: 'X-Idempotency-Key header is required', code: 'MISSING_IDEMPOTENCY_KEY' });
    return;
  }

  if (!UUID_V4_REGEX.test(key)) {
    res.status(400).json({ success: false, error: 'X-Idempotency-Key must be a valid UUIDv4', code: 'INVALID_IDEMPOTENCY_KEY' });
    return;
  }

  const cacheKey = `campusops:idempotency:${key}`;
  const redis = getRedisClient();

  redis.get(cacheKey).then((cached) => {
    if (cached) {
      logger.info({ msg: 'Idempotency cache hit', key, correlationId: req.correlationId });
      const { status, body } = JSON.parse(cached) as { status: number; body: unknown };
      res.status(status).json(body);
      return;
    }

    // Intercept response to cache it
    const originalJson = res.json.bind(res);
    res.json = (body) => {
      if (res.statusCode < 500) {
        redis
          .setex(cacheKey, IDEMPOTENCY_TTL_SECONDS, JSON.stringify({ status: res.statusCode, body }))
          .catch((err) => logger.error({ msg: 'Failed to cache idempotency response', err }));
      }
      return originalJson(body);
    };

    next();
  }).catch((err) => {
    logger.error({ msg: 'Idempotency Redis lookup failed â€” failing open', err });
    next(); // Fail open
  });
}

