import { Request, Response, NextFunction } from 'express';
import crypto from 'crypto';
import { logger } from '../lib/logger';

/**
 * HMAC-SHA256 API signing middleware for privileged integrations
 * (classroom hardware, parking ingest, carrier connectors).
 *
 * Expected request headers:
 *   X-Api-Key    â€” identifies the integration (looked up in DB)
 *   X-Timestamp  â€” Unix timestamp (ms), rejected if >5 min old
 *   X-Signature  â€” HMAC-SHA256(secret, `${method}:${path}:${timestamp}:${body}`)
 */
export function apiSigning(getSecretByKey: (apiKey: string) => Promise<string | null>) {
  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    const apiKey = req.headers['x-api-key'] as string | undefined;
    const timestamp = req.headers['x-timestamp'] as string | undefined;
    const signature = req.headers['x-signature'] as string | undefined;

    if (!apiKey || !timestamp || !signature) {
      res.status(401).json({ success: false, error: 'Missing API signing headers', code: 'MISSING_API_SIGNING' });
      return;
    }

    const tsMs = parseInt(timestamp, 10);
    if (isNaN(tsMs) || Math.abs(Date.now() - tsMs) > 5 * 60 * 1000) {
      res.status(401).json({ success: false, error: 'Request timestamp out of acceptable range', code: 'TIMESTAMP_EXPIRED' });
      return;
    }

    const secret = await getSecretByKey(apiKey);
    if (!secret) {
      res.status(401).json({ success: false, error: 'Unknown API key', code: 'UNKNOWN_API_KEY' });
      return;
    }

    const body = typeof req.body === 'object' ? JSON.stringify(req.body) : (req.body ?? '');
    const signaturePayload = `${req.method}:${req.path}:${timestamp}:${body}`;
    const expected = crypto.createHmac('sha256', secret).update(signaturePayload).digest('hex');

    if (signature.length !== expected.length ||
        !crypto.timingSafeEqual(Buffer.from(signature, 'hex'), Buffer.from(expected, 'hex'))) {
      logger.warn({ msg: 'Invalid API signature', apiKey, path: req.path });
      res.status(401).json({ success: false, error: 'Invalid signature', code: 'INVALID_SIGNATURE' });
      return;
    }

    next();
  };
}

/**
 * Looks up the HMAC secret for a given API key ID from the IntegrationKey table.
 * Used as the getSecretByKey callback for apiSigning middleware.
 */
export async function getSecretByKeyId(apiKeyId: string): Promise<string | null> {
  try {
    const { prisma } = await import('../lib/prisma');
    const key = await prisma.integrationKey.findUnique({ where: { keyId: apiKeyId } });
    if (!key || !key.isActive) return null;
    // Update lastUsedAt without blocking
    prisma.integrationKey.update({ where: { id: key.id }, data: { lastUsedAt: new Date() } }).catch(() => {});
    return key.secretHash;
  } catch (err) {
    logger.error({ msg: 'Failed to lookup integration key', apiKeyId, err });
    return null;
  }
}

/** Pre-configured API signing middleware using DB-backed key lookup */
export const privilegedApiSigning = apiSigning(getSecretByKeyId);

