  const tableCountFns: Array<{ name: string; fn: () => Promise<number> }> = [
    { name: 'User',               fn: () => (prisma as any).user?.count?.()             ?? Promise.resolve(0) },
    { name: 'Role',               fn: () => (prisma as any).role?.count?.()             ?? Promise.resolve(0) },
