      .post('/api/stored-value/some-student-id/top-up')
      .send({ amount: 50 });
    expect(res.status).toBe(401);
  });

  it('requires idempotency key', async () => {
    const token = await loginAs('admin');
    const res = await request(app)
      .post('/api/stored-value/some-student-id/top-up')
      .set('Authorization', `Bearer ${token}`)
